{
  "title": "स्ट्रीम पाइपिंग",
  "group": "स्ट्रीम",
  "options": [
    {
      "text": "फ़ाइल को संपीड़ित करके कॉपी करता है"
    },
    {
      "text": "मेमोरी बफ़रिंग के बिना फ़ाइल कॉपी करता है",
      "hint": "सही उत्तर: `pipe()` छोटे चंक्स में डेटा कॉपी करता है"
    },
    {
      "text": "पूरी फ़ाइल को मेमोरी में लोड करता है"
    },
    {
      "text": "एक सिम्बोलिक लिंक बनाता है"
    }
  ],
  "questionProse": [
    "इस कोड का क्या कार्य है?"
  ],
  "explanationProse": [
    "`pipe()` एक पढ़ने योग्य स्ट्रीम को लिखने योग्य स्ट्रीम से जोड़ता है, ऑटोमैटिक रूप से बैकप्रेशर को मैनेज करता है और पूरी फ़ाइल को मेमोरी में लोड किए बिना डेटा के चंक्स कॉपी करता है।\n\n    बड़ी फ़ाइलों के लिए यह `fs.readFile()` और `fs.writeFile()` की तुलना में मेमोरी दक्ष होता है।\n\n    [pipe() के बारे में अधिक जानें](https://nodejs.org/api/stream.html#readablepipedestination-options)"
  ]
}
